+    tracing::info!("Google Chat raw payload ({} bytes): {}...", body.len(), &raw_str[..raw_str.len().min(300)]);

-    // Parse body manually for resilience — log raw payload on failure
-    let event: GoogleChatEvent = match serde_json::from_slice(&body) {
-        Ok(e) => e,
